(29, 'b-1777205765', 'C# Programming', '94e1fdc9094692e4e247c5b4ed2d319a02af0fc231f38f58a53c4270f2499fe4', '&lt;p&gt;មាននៅក្នុងបណ្ណាល័យតេជោសន្តិភាព នៃពុទ្ធិកសាកលវិទ្យាល័យព្រះសីហមុនីរាជា&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;color: rgb(68, 68, 68); font-family: KanProEL; font-size: 15px; text-align: justify;&quot;&gt;ព្រះករុណាខ្ញុំ អាត្មាភាព សម្ដេចព្រះអភិសិរីសុគន្ធាមហាសង្ឃរាជាធិបតីកិតិ្តឧទេ្ទសបណ្ឌិត បួរ គ្រី ជាព្រះសាកលវិទ្យាធិការ នៃពុទ្ធិកសាកលវិទ្យាល័យព្រះសីហមុនីរាជា សង្ឃឹមនិងជឿជាក់ដោយមានទស្សនវិស័យ​ច្បាស់លាស់ បេសកកម្មត្រឹមត្រូវ គោលដៅជាក់លាក់មានការប្តេជ្ញាចិត្តខ្ពស់ ក្នុងការជំរុញសមណនិស្សិត-និស្សិតមានសមត្ថភាពគ្រប់គ្រងខ្លួនឯង ដឹកនាំគ្រួសារ និងចេះរស់នៅក្នុងសង្គម តាមបាវចនា មេត្តា សតិ បញ្ញា&nbsp;&nbsp;នឹងក្លាយជាធនធានបញ្ញាដ៏មានប្រយោជន៍ប្រកបដោយសីលធម៌ និងគុណធម៌ខ្ពស់ ដែលអាចចូលរួមចំណែកក្នុងការអភិវឌ្ឍសង្គមជាតិ ឱ្យសម្បូររុងរឿងនាពេលអនាគត ។&lt;/span&gt;&lt;/p&gt;', 'csharp_programming', 0, 'Microsoft', '2026-06-09', 11, 13, 54, '2026-06-06 08:31:52', '2026-06-06 08:44:10', 0.0000, NULL);

