(16, 'historical_romance', 'Historical romance', NULL, NULL, 'historical_romance', '&lt;p&gt;&lt;strong style=&quot;color: rgb(0, 29, 53); font-family: &quot;Google Sans&quot;, Arial, sans-serif;&quot;&gt;Historical romance&nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(84, 93, 126); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.1px;&quot;&gt;A genre that features romance stories set in a specific historic era&lt;/span&gt;&lt;/p&gt;', 0, NULL, NULL),
(17, 'magical_realism', 'Magical realism', NULL, NULL, 'magical_realism', '&lt;p&gt;&lt;strong style=&quot;color: rgb(0, 29, 53); font-family: &quot;Google Sans&quot;, Arial, sans-serif;&quot;&gt;Magical realism&nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(84, 93, 126); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.1px;&quot;&gt;A genre that depicts the world truthfully, but also adds magical elements that are considered normal in the story&#039;s world&lt;/span&gt;&lt;/p&gt;', 0, NULL, NULL),
(18, 'children\'s_literature', 'Children\'s literature', NULL, NULL, 'children\'s_literature', '&lt;p&gt;&lt;strong style=&quot;color: rgb(0, 29, 53); font-family: &quot;Google Sans&quot;, Arial, sans-serif;&quot;&gt;Children&#039;s literature&nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(84, 93, 126); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.1px;&quot;&gt;A genre that aims to impart a lesson to the reader, and often features tropes such as talking animals, the power of friendship, and appreciating differences&lt;/span&gt;&lt;/p&gt;', 0, NULL, NULL),
(19, 'list_stories', 'List stories', NULL, NULL, 'list_stories', '&lt;p&gt;&lt;strong style=&quot;color: rgb(0, 29, 53); font-family: &quot;Google Sans&quot;, Arial, sans-serif;&quot;&gt;List stories&nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(84, 93, 126); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.1px;&quot;&gt;A genre that is written as or structured around lists&lt;/span&gt;&lt;/p&gt;', 0, NULL, NULL),
(20, 'history', 'History', NULL, NULL, 'history', '&lt;span style=&quot;color: rgb(77, 81, 86); font-family: Arial, sans-serif; font-size: 14px;&quot;&gt;History is the systematic study and documentation of the human past. History is an academic discipline which uses a narrative to describe, examine, question, and analyse past events, and investigate their patterns of cause and effect.&lt;/span&gt;', 0, NULL, NULL),
(21, 'រឿងខ្មែរ', 'រឿងខ្មែរ', NULL, 14, 'រឿងខ្មែរ', '&lt;p&gt;រឿងខ្មែរ&lt;/p&gt;', 0, NULL, NULL);

